code = """import json

# Access the business data directly from storage
businesses = locals()['var_functions.query_db:10']

# Extract businesses that accept credit cards and their categories
credit_card_businesses = []
for business in businesses:
    attributes = business.get('attributes')
    if isinstance(attributes, dict) and attributes.get('BusinessAcceptsCreditCards') == 'True':
        description = business.get('description', '')
        
        # Extract categories from description
        categories = []
        if 'services in' in description:
            parts = description.split('services in')
            if len(parts) > 1:
                category_text = parts[1].strip().rstrip('.')
                categories = [cat.strip() for cat in category_text.split(',')]
        elif 'services including' in description:
            parts = description.split('services including')
            if len(parts) > 1:
                category_text = parts[1].strip().rstrip('.')
                categories = [cat.strip() for cat in category_text.split(',')]
        elif 'category of' in description:
            parts = description.split('category of')
            if len(parts) > 1:
                category_text = parts[1].strip().rstrip('.').strip("'")
                categories = [cat.strip() for cat in category_text.split(',')]
        
        # Clean categories
        cleaned_categories = []
        for category in categories:
            if category.startswith('and '):
                cleaned_categories.append(category[4:].strip())
            elif category and category != 'Local Services':
                cleaned_categories.append(category)
            elif category == 'Local Services':
                cleaned_categories.append(category)
        
        credit_card_businesses.append({
            'business_id': business['business_id'],
            'name': business['name'],
            'categories': cleaned_categories
        })

# Count category frequencies
category_counts = {}
for business in credit_card_businesses:
    for category in business['categories']:
        if category:
            category_counts[category] = category_counts.get(category, 0) + 1

# Find most common category
most_common_category = None
most_common_count = 0
if category_counts:
    most_common_category, most_common_count = max(category_counts.items(), key=lambda x: x[1])

print('__RESULT__:')
print(json.dumps({
    'total_credit_card_businesses': len(credit_card_businesses),
    'most_common_category': most_common_category,
    'most_common_count': most_common_count,
    'category_counts': dict(sorted(category_counts.items(), key=lambda x: x[1], reverse=True)[:15])
}))"""

